package com.yottastudios.ns.collabspace.announcement.controller;

import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementStatus;
import com.yottastudios.ns.collabspace.announcement.ro.CreateAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.ro.DeleteAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.ro.RepublishAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.ro.UpdateAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.service.IAnnouncementService;
import com.yottastudios.ns.collabspace.announcement.vo.ActiveAnnouncementVo;
import com.yottastudios.ns.collabspace.announcement.vo.CreateAnnouncementVo;
import com.yottastudios.ns.collabspace.announcement.vo.GetListAnnouncementVo;
import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.GetResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import com.yottastudios.ns.collabspace.shared.config.properties.ConstProperties;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import jakarta.validation.Valid;
import lombok.extern.slf4j.Slf4j;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

@Slf4j
@RestController
@Tag(name = "Announcement")
@ApiResource(path = "/announcement")
public class AnnouncementController {

    @Resource
    private IAnnouncementService announcementService;

    @Resource
    ConstProperties constProperties;


    /**
     * 创建公告
     */
    @PostResource(path = "/create", requiredPermission = false)
    @Operation(summary = "Create Announcement")
    public ResponseData<Void> createAnnouncement(@RequestBody @Valid CreateAnnouncementRo ro) {
        announcementService.createAnnouncement(ro);
        return ResponseData.success();
    }

    /**
     * 获取待发布列表
     * @return List<GetListAnnouncementVo>
     */
    @GetResource(path = "/list/waiting", requiredPermission = false)
    @Operation(summary = "list waiting")
    public ResponseData<List<GetListAnnouncementVo>> getWaitingAnnouncement(
            @RequestParam(required = false) String spaceId,
            @RequestParam(required = false) Integer announcementCategory) {
        List<GetListAnnouncementVo> voList = announcementService.getAnnounceList(
                AnnouncementStatus.WAITING.getCode(), spaceId, announcementCategory);
        return ResponseData.success(voList);
    }

    /**
     * 获取发布列表（已移除自动标记已读，请通过 /announcement/read 显式标记）
     * @return List<GetListAnnouncementVo>
     */
    @GetResource(path = "/list/published", requiredPermission = false)
    @Operation(summary = "list published")
    public ResponseData<List<GetListAnnouncementVo>> getPublishedAnnouncement(
            @RequestParam(required = false) String spaceId,
            @RequestParam(required = false) Integer announcementCategory) {
        List<GetListAnnouncementVo> voList = announcementService.getAnnounceList(
                AnnouncementStatus.PUBLISHED.getCode(), spaceId, announcementCategory);
        return ResponseData.success(voList);
    }

    /**
     * 修改公告状态
     */
    @PostResource(path = "/update", requiredPermission = false)
    @Operation(summary = "update status or type")
    public ResponseData<Void> changeAnnouncementStatus(@RequestBody @Valid UpdateAnnouncementRo ro) {
        Boolean success = announcementService.changeAnnouncementStatus(ro);
        return success ? ResponseData.success() : ResponseData.error();
    }

    /**
     * 获取最新公告
     * @return GetListAnnouncementVo
     */
    @GetResource(path = "/last", requiredPermission = false)
    @Operation(summary = "get last one")
    public ResponseData<GetListAnnouncementVo> getLastAnnouncement() {
        GetListAnnouncementVo vo = announcementService.getLastAnnouncement();
        return ResponseData.success(vo);
    }


    @GetResource(path = "/redpots", requiredPermission = false)
    @Operation(summary = "red pots view")
    public ResponseData<Boolean> judgeRedPots(@RequestParam(required = false) String spaceId) {
        return ResponseData.success(announcementService.judgeRedPots(spaceId));
    }

    /**
     * 获取历史公告列表
     */
    @GetResource(path = "/list/history", requiredPermission = false)
    @Operation(summary = "获取历史公告列表")
    public ResponseData<List<GetListAnnouncementVo>> getHistoryList(
            @RequestParam(required = false) String spaceId,
            @RequestParam(required = false) Integer announcementCategory) {
        return ResponseData.success(announcementService.getHistoryList(spaceId, announcementCategory));
    }

    /**
     * 软删除公告
     */
    @PostResource(path = "/delete", requiredPermission = false)
    @Operation(summary = "软删除公告")
    public ResponseData<Boolean> deleteAnnouncement(@RequestBody @Valid DeleteAnnouncementRo ro) {
        return ResponseData.success(announcementService.deleteAnnouncement(ro.getAnnouncementId()));
    }

    /**
     * 基于历史公告重新发布
     */
    @PostResource(path = "/republish", requiredPermission = false)
    @Operation(summary = "基于历史公告重新发布")
    public ResponseData<CreateAnnouncementVo> republishAnnouncement(@RequestBody @Valid RepublishAnnouncementRo ro) {
        return ResponseData.success(announcementService.republishAnnouncement(ro));
    }

    /**
     * 获取当前生效公告（空间站+平台，最多2条）
     */
    @GetResource(path = "/active", requiredPermission = false)
    @Operation(summary = "获取当前生效公告（空间站+平台，最多2条）")
    public ResponseData<List<ActiveAnnouncementVo>> getActiveAnnouncements(
            @RequestParam(required = false) String spaceId) {
        return ResponseData.success(announcementService.getActiveAnnouncements(spaceId));
    }

    /**
     * 标记公告已读（显式调用）
     */
    @PostResource(path = "/read", requiredPermission = false)
    @Operation(summary = "标记公告已读")
    public ResponseData<Void> markAnnouncementRead(
            @RequestParam Long announcementId,
            @RequestParam(required = false) String spaceId) {
        announcementService.addAnnouncementReadRecord(announcementId, spaceId);
        return ResponseData.success(null);
    }

    @Operation(summary = "sync announcement from exact NET to inter NET")
    @Scheduled(cron = "0 0/1 * * * ?")
    public void syncAnnouncement() {
        // 仅限内网但不是镜像服
        boolean internalNetwork = constProperties.isInternalNetwork() && !constProperties.isMirror();
        if (!internalNetwork)
            return;
        announcementService.syncAnnouncement();
    }
}

package com.yottastudios.ns.collabspace.manageback.controller;

import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementCategory;
import com.yottastudios.ns.collabspace.announcement.enums.AnnouncementStatus;
import com.yottastudios.ns.collabspace.announcement.ro.CreateAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.ro.DeleteAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.ro.UpdateAnnouncementRo;
import com.yottastudios.ns.collabspace.announcement.service.IAnnouncementService;
import com.yottastudios.ns.collabspace.announcement.vo.CreateAnnouncementVo;
import com.yottastudios.ns.collabspace.announcement.vo.GetListAnnouncementVo;
import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.GetResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.validation.Valid;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.util.ArrayList;
import java.util.List;

@Slf4j
@RestController
@Tag(name = "管理后台-平台公告管理")
@ApiResource(path = "/manageback/announcement")
@RequiredArgsConstructor
public class ManagebackAnnouncementController {

    private final IAnnouncementService announcementService;

    /**
     * 创建平台公告（强制设为平台类型，不绑定空间站）
     */
    @PostResource(path = "/create", requiredPermission = false)
    @Operation(summary = "创建平台公告")
    public ResponseData<CreateAnnouncementVo> createPlatformAnnouncement(@RequestBody @Valid CreateAnnouncementRo ro) {
        ro.setAnnouncementCategory(AnnouncementCategory.PLATFORM.getCode());
        ro.setSpaceId(null);
        return ResponseData.success(announcementService.createAnnouncement(ro));
    }

    /**
     * 平台公告列表：
     * - 指定 status 则按状态过滤
     * - 不传 status 则合并所有状态（发布中、待发布、定时、历史）
     */
    @GetResource(path = "/list", requiredPermission = false)
    @Operation(summary = "平台公告列表")
    public ResponseData<List<GetListAnnouncementVo>> listPlatformAnnouncements(
            @RequestParam(required = false) Integer status) {
        if (status != null) {
            return ResponseData.success(announcementService.getAnnounceList(
                    status, null, AnnouncementCategory.PLATFORM.getCode()));
        }
        // 汇总所有状态的平台公告
        List<GetListAnnouncementVo> result = new ArrayList<>();
        result.addAll(announcementService.getAnnounceList(
                AnnouncementStatus.PUBLISHED.getCode(), null, AnnouncementCategory.PLATFORM.getCode()));
        result.addAll(announcementService.getAnnounceList(
                AnnouncementStatus.WAITING.getCode(), null, AnnouncementCategory.PLATFORM.getCode()));
        result.addAll(announcementService.getAnnounceList(
                AnnouncementStatus.TIMED.getCode(), null, AnnouncementCategory.PLATFORM.getCode()));
        result.addAll(announcementService.getHistoryList(null, AnnouncementCategory.PLATFORM.getCode()));
        return ResponseData.success(result);
    }

    /**
     * 修改/下线平台公告
     */
    @PostResource(path = "/update", requiredPermission = false)
    @Operation(summary = "修改/下线平台公告")
    public ResponseData<Boolean> updatePlatformAnnouncement(@RequestBody @Valid UpdateAnnouncementRo ro) {
        return ResponseData.success(announcementService.changeAnnouncementStatus(ro));
    }

    /**
     * 软删除平台公告
     */
    @PostResource(path = "/delete", requiredPermission = false)
    @Operation(summary = "软删除平台公告")
    public ResponseData<Boolean> deletePlatformAnnouncement(@RequestBody @Valid DeleteAnnouncementRo ro) {
        return ResponseData.success(announcementService.deleteAnnouncement(ro.getAnnouncementId()));
    }
}
